import { PATH_ELEMENT } from '../../../../core/element-constants';
import { SLIDER_HANDLE_TRACK_CLASSNAME, CUSTOM_HANDLE_PATH_CLASSNAME } from '../../../../legend/legend-constants';
import { CHART_BRUSH_HELPERS } from '../../../../brush/chart-helpers/brush-helpers';
import { d3_select, d3_line, d3_curves } from '../../../../core/d3-constants';
import { bbox } from '../../../../utils/zcutils';

export function AddClipToHandles(behaviourEventInstance, selectionManager) {
    let _instance = behaviourEventInstance.instance,
        customHandles = _instance.customHandles,
        eventManager = this,
        chart = eventManager.chart;

    if (!customHandles) {
        return;
    }

    let { brushOptions } = _instance.options.component,
        { isHorizontal, handles: handleOptions } = brushOptions;

    if (handleOptions) {
        customHandles.each(function(d, i) {
            let handleEle = d3_select(this).selectAll(`${PATH_ELEMENT}.${CUSTOM_HANDLE_PATH_CLASSNAME}`),
                handleNodes = handleEle.nodes();

            if (!handleNodes[1]) {
                return;
            }

            let desc = clip4Handle(bbox(handleNodes[0]), i, isHorizontal),
                clipSrc = CHART_BRUSH_HELPERS.GET_CLIP(_instance, [0, 0], chart, `size_slider_brush_handle_${i}`, { desc });

            d3_select(handleNodes[1])
                .attr('clip-path', clipSrc)
                .style('opacity', 0)
                .classed(SLIDER_HANDLE_TRACK_CLASSNAME, true);
        });
    }
}

function clip4Handle(bb, i, isHorizontal) {
    let { x, y, width, height } = bb,
        strokeWidth = 1,
        lineClosed = d3_line().curve(d3_curves('linear-closed')),
        points;

    if (isHorizontal) {
        if (i === 0) {
            points = [
                [0, y - strokeWidth],
                [x + width + strokeWidth, y - strokeWidth],
                [x + width + strokeWidth, y + height + strokeWidth],
                [0, y + height + strokeWidth]
            ];
        } else {
            points = [
                [x - strokeWidth, y - strokeWidth],
                [0, y - strokeWidth],
                [0, y + height + strokeWidth],
                [x - strokeWidth, y + height + strokeWidth]
            ];
        }
    } else {
        if (i === 0) {
            points = [
                [x - strokeWidth, 0],
                [x + width + strokeWidth, 0],
                [x + width + strokeWidth, y + height + strokeWidth],
                [x - strokeWidth, y + height + strokeWidth]
            ];
        } else {
            points = [
                [x - strokeWidth, y - strokeWidth],
                [x + width + strokeWidth, y - strokeWidth],
                [x + width + strokeWidth, 0],
                [x - strokeWidth, 0]
            ];
        }
    }

    return lineClosed(points);
}
